 1→import { useState } from "react";
 2→import { X } from "lucide-react";
 3→
 4→interface GenerateDialogProps {
 5→  date: string;
 6→  onClose: () => void;
 7→  onGenerate: (date: string, extraItems?: string[]) => void;
 8→}
 9→
10→export function GenerateDialog({ date, onClose, onGenerate }: GenerateDialogProps) {
11→  const [extraItems, setExtraItems] = useState("");
12→
13→  const formattedDate = new Date(date + "T12:00:00").toLocaleDateString("en-US", {
14→    weekday: "long",
15→    month: "long",
16→    day: "numeric",
17→  });
18→
19→  const handleGenerate = () => {
20→    const items = extraItems
21→      .split("\n")
22→      .map((line) => line.replace(/^[-*]\s*/, "").trim())
23→      .filter((line) => line.length > 0);
24→
25→    onGenerate(date, items.length > 0 ? items : undefined);
26→    onClose();
27→  };
28→
29→  return (
30→    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
31→      <div className="w-[520px] rounded-lg border border-border bg-bg-raised shadow-xl">
32→        <div className="flex items-center justify-between border-b border-border px-6 py-4">
33→          <h2 className="text-sm font-semibold text-fg">Generate Daily Summary</h2>
34→          <button
35→            onClick={onClose}
36→            className="text-fg-subtle hover:text-fg"
37→          >
38→            <X size={16} />
39→          </button>
40→        </div>
41→
42→        <div className="p-6">
43→          <div className="mb-1 text-sm font-semibold text-fg">
44→            Generate summary for {formattedDate}
45→          </div>
46→
47→          <div className="mb-5 mt-4">
48→            <label className="mb-1.5 block text-[11px] font-semibold uppercase text-fg-muted">
49→              Anything else to include?
50→            </label>
51→            <div className="mb-2 text-[11px] text-fg-subtle">
52→              Add non-code work — meetings, reviews, planning, design sessions, etc.
53→            </div>
54→            <textarea
55→              value={extraItems}
56→              onChange={(e) => setExtraItems(e.target.value)}
57→              className="w-full rounded-md border border-border bg-bg p-2.5 text-xs leading-relaxed text-fg placeholder:text-fg-subtle focus:border-accent focus:outline-none"
58→              rows={4}
59→              placeholder={"e.g.\n- Led sprint planning, scoped Q2 milestones\n- Reviewed 2 architecture RFCs\n- Paired with Sarah on auth migration design"}
60→            />
61→          </div>
62→
63→          <div className="flex justify-end gap-2">
64→            <button
65→              onClick={onClose}
66→              className="rounded-md border border-border bg-bg px-4 py-2 text-xs text-fg hover:bg-bg-hover"
67→            >
68→              Cancel
69→            </button>
70→            <button
71→              onClick={handleGenerate}
72→              className="rounded-md bg-accent px-4 py-2 text-xs font-semibold text-white hover:bg-accent/90"
73→            >
74→              ✨ Generate
75→            </button>
76→          </div>
77→        </div>
78→      </div>
79→    </div>
80→  );
81→}
