 1→import { useState, useRef, useCallback } from "react";
 2→import { Loader2, X } from "lucide-react";
 3→import { useJournalEntriesQuery, useJournalDatesQuery, useGenerateJournalMutation } from "../../hooks/use-tauri-query";
 4→import { JournalFeed } from "./JournalFeed";
 5→import { DateJumper } from "./DateJumper";
 6→import { GenerateDialog } from "./GenerateDialog";
 7→
 8→export function DashboardView() {
 9→  const [showGenerateDialog, setShowGenerateDialog] = useState(false);
10→  const [showErrorBanner, setShowErrorBanner] = useState(true);
11→  const feedRef = useRef<HTMLDivElement>(null);
12→
13→  const { data: entries = [] } = useJournalEntriesQuery();
14→  const { data: dates = [] } = useJournalDatesQuery();
15→  const generateMutation = useGenerateJournalMutation();
16→
17→  const today = new Date().toISOString().slice(0, 10);
18→
19→  const handleDateClick = useCallback((date: string) => {
20→    const el = document.getElementById(`journal-${date}`);
21→    if (el) {
22→      el.scrollIntoView({ behavior: "smooth", block: "start" });
23→    }
24→  }, []);
25→
26→  const handleGenerate = useCallback(
27→    (date: string, extraItems?: string[]) => {
28→      setShowErrorBanner(true);
29→      generateMutation.mutate({ date, extraItems });
30→    },
31→    [generateMutation]
32→  );
33→
34→  return (
35→    <div className="flex flex-1 flex-col overflow-hidden">
36→      {/* Dashboard toolbar */}
37→      <div className="flex items-center justify-between border-b border-border bg-bg px-5 py-3">
38→        <div className="flex items-center gap-3">
39→          <h1 className="text-sm font-semibold text-fg">Work Journal</h1>
40→        </div>
41→        <button
42→          onClick={() => setShowGenerateDialog(true)}
43→          disabled={generateMutation.isPending}
44→          className="rounded-md bg-accent px-3 py-1.5 text-xs font-semibold text-white hover:bg-accent/90 disabled:opacity-50"
45→        >
46→          ✨ Generate Today's Summary
47→        </button>
48→      </div>
49→
50→      {/* Generation status banner */}
51→      {generateMutation.isPending && (
52→        <div className="flex items-center gap-2 border-b border-border bg-accent/5 px-5 py-2.5">
53→          <Loader2 size={14} className="animate-spin text-accent" />
54→          <span className="text-xs text-fg-subtle">
55→            Generating summary… this may take a minute or two
56→          </span>
57→        </div>
58→      )}
59→
60→      {generateMutation.isError && showErrorBanner && (
61→        <div className="flex items-center justify-between border-b border-red-500/20 bg-red-500/5 px-5 py-2.5">
62→          <span className="text-xs text-red-500">
63→            Generation failed: {generateMutation.error.message}
64→          </span>
65→          <button
66→            onClick={() => setShowErrorBanner(false)}
67→            className="text-red-500 hover:text-red-400"
68→          >
69→            <X size={14} />
70→          </button>
71→        </div>
72→      )}
73→
74→      {/* Feed + Date Jumper */}
75→      <div className="flex flex-1 overflow-hidden">
76→        <div ref={feedRef} className="flex-1 overflow-y-auto px-8 py-6">
77→          <div className="mx-auto max-w-[720px]">
78→            <JournalFeed entries={entries} />
79→          </div>
80→        </div>
81→
82→        <DateJumper dates={dates} onDateClick={handleDateClick} />
83→      </div>
84→
85→      {/* Generate dialog */}
86→      {showGenerateDialog && (
87→        <GenerateDialog
88→          date={today}
89→          onClose={() => setShowGenerateDialog(false)}
90→          onGenerate={handleGenerate}
91→        />
92→      )}
93→    </div>
94→  );
95→}
