  1→use crate::checkpoint;
  2→use crate::config;
  3→use crate::git;
  4→use crate::journal;
  5→use crate::journal::github;
  6→use crate::{AnthropicMessage, AnthropicRequest, AnthropicResponse};
  7→
  8→/// Gather checkpoint data for a specific date from a repo.
  9→fn gather_day_data(repo_path: &str, date: &str) -> Result<DayData, String> {
 10→    let repo = git::open_repo(repo_path)?;
 11→
 12→    // List all checkpoints (no branch filter — we want cross-branch)
 13→    let all_checkpoints = checkpoint::list_checkpoints(&repo, "")?;
 14→
 15→    // Filter to checkpoints created on the target date
 16→    let day_checkpoints: Vec<_> = all_checkpoints
 17→        .into_iter()
 18→        .filter(|cp| cp.created_at.starts_with(date))
 19→        .collect();
 20→
 21→    // Filter to only the current user's checkpoints based on git user.email
 22→    let user_email = repo
 23→        .config()
 24→        .ok()
 25→        .and_then(|c| c.get_string("user.email").ok())
 26→        .unwrap_or_default()
 27→        .to_lowercase();
 28→
 29→    let day_checkpoints: Vec<_> = if user_email.is_empty() {
 30→        day_checkpoints // Can't determine user — include all
 31→    } else {
 32→        day_checkpoints
 33→            .into_iter()
 34→            .filter(|cp| {
 35→                cp.commit_author_email.is_empty() // Unknown author — include
 36→                    || cp.commit_author_email.to_lowercase() == user_email
 37→            })
 38→            .collect()
 39→    };
 40→
 41→    let mut total_sessions: u64 = 0;
 42→    let mut total_tokens: u64 = 0;
 43→    let mut total_agent_pct_sum: f64 = 0.0;
 44→    let mut total_agent_pct_count: u64 = 0;
 45→
 46→    let mut summaries = Vec::new();
 47→
 48→    for cp in &day_checkpoints {
 49→        total_sessions += cp.sessions.len() as u64;
 50→        if let Some(ref tu) = cp.token_usage {
 51→            total_tokens += tu.input_tokens + tu.output_tokens;
 52→        }
 53→
 54→        for session in &cp.sessions {
 55→            if let Some(ref attr) = session.initial_attribution {
 56→                total_agent_pct_sum += attr.agent_percentage;
 57→                total_agent_pct_count += 1;
 58→            }
 59→
 60→            let intent = session
 61→                .summary
 62→                .as_ref()
 63→                .map(|s| s.intent.clone())
 64→                .unwrap_or_default();
 65→            let outcome = session
 66→                .summary
 67→                .as_ref()
 68→                .map(|s| s.outcome.clone())
 69→                .unwrap_or_default();
 70→
 71→            summaries.push(format!(
 72→                "- [{}] {}: {} → {}",
 73→                cp.branch, cp.commit_message, intent, outcome
 74→            ));
 75→        }
 76→    }
 77→
 78→    let avg_ai_pct = if total_agent_pct_count > 0 {
 79→        (total_agent_pct_sum / total_agent_pct_count as f64).round() as u64
 80→    } else {
 81→        0
 82→    };
 83→
 84→    // Gather files touched
 85→    let files_touched: Vec<String> = day_checkpoints
 86→        .iter()
 87→        .flat_map(|cp| cp.files_touched.iter().cloned())
 88→        .collect::<std::collections::HashSet<_>>()
 89→        .into_iter()
 90→        .collect();
 91→
 92→    let lines_changed = files_touched.len() as u64 * 30; // rough estimate
 93→
 94→    Ok(DayData {
 95→        summaries,
 96→        files_touched,
 97→        total_sessions,
 98→        total_tokens,
 99→        avg_ai_pct,
100→        lines_changed,
101→    })
102→}
103→
104→struct DayData {
105→    summaries: Vec<String>,
106→    files_touched: Vec<String>,
107→    total_sessions: u64,
108→    total_tokens: u64,
109→    avg_ai_pct: u64,
110→    lines_changed: u64,
111→}
