113→/// Build a Claude prompt that aggregates data from multiple repos.
114→fn build_multi_repo_prompt(
115→    date: &str,
116→    repo_data: &[(String, DayData, Vec<journal::JournalPR>)],
117→    extra_items: &[String],
118→) -> String {
119→    let mut prompt = format!(
120→        "Generate a daily work journal entry for {} across all repositories.\n\n",
121→        date
122→    );
123→
124→    for (repo_name, day_data, prs) in repo_data {
125→        prompt.push_str(&format!("# Repository: {}\n\n", repo_name));
126→
127→        prompt.push_str("## Session Activity\n");
128→        if day_data.summaries.is_empty() {
129→            prompt.push_str("No code sessions recorded for this day.\n");
130→        } else {
131→            for s in &day_data.summaries {
132→                prompt.push_str(&format!("{}\n", s));
133→            }
134→        }
135→
136→        if !day_data.files_touched.is_empty() {
137→            prompt.push_str("\n## Files Touched\n");
138→            for f in &day_data.files_touched {
139→                prompt.push_str(&format!("- {}\n", f));
140→            }
141→        }
142→
143→        if !prs.is_empty() {
144→            prompt.push_str("\n## Pull Requests\n");
145→            for pr in prs {
146→                prompt.push_str(&format!(
147→                    "- #{} \"{}\" ({})\n",
148→                    pr.number, pr.title, pr.status
149→                ));
150→            }
151→        }
152→
153→        prompt.push('\n');
154→    }
155→
156→    if !extra_items.is_empty() {
157→        prompt.push_str("# Non-Code Work (provided by user)\n");
158→        for item in extra_items {
159→            prompt.push_str(&format!("- {}\n", item));
160→        }
161→    }
162→
163→    prompt.push_str("\n## Instructions\n");
164→    prompt.push_str("Respond with ONLY a JSON object (no markdown fences) in this exact format:\n");
165→    prompt.push_str(
166→        r#"{
167→  "repos": [
168→    {
169→      "name": "repo-name",
170→      "accomplishments": ["concise action-oriented bullet point", ...]
171→    }
172→  ],
173→  "other_work": ["non-code item", ...]
174→}
175→"#,
176→    );
177→    prompt.push_str("\nRules:\n");
178→    prompt.push_str("- Group accomplishments by repository name — use the exact repo names from above\n");
179→    prompt.push_str("- Only include repos that had activity (sessions, PRs, or file changes)\n");
180→    prompt.push_str(
181→        "- Write concise, action-oriented bullet points suitable for standup reporting\n",
182→    );
183→    prompt.push_str("- Summarize accomplishments, don't just repeat commit messages\n");
184→    prompt.push_str(
185→        "- Include the user's non-code work items in other_work exactly as provided\n",
186→    );
187→    prompt
188→        .push_str("- If there are no sessions or PRs, still return the structure with empty arrays\n");
189→
190→    if let Some(ref fmt) = config::read_app_settings().journal_format {
191→        if !fmt.is_empty() {
192→            prompt.push_str("\n## User's Format Preferences\n");
193→            prompt.push_str("The user has specified these formatting preferences. Follow them:\n");
194→            prompt.push_str(fmt);
195→            prompt.push('\n');
196→        }
197→    }
198→
199→    prompt
200→}
