215→/// Generate a journal entry for a given date, aggregating across all registered repos.
216→pub fn generate_entry(
217→    date: &str,
218→    extra_items: Option<Vec<String>>,
219→) -> Result<journal::JournalEntry, String> {
220→    let extra = extra_items.unwrap_or_default();
221→    let repo_paths = config::discover_repos();
222→
223→    if repo_paths.is_empty() {
224→        return Err("No registered repos found. Register a repo first.".to_string());
225→    }
226→
227→    // Gather data from all repos
228→    let mut all_repo_data: Vec<(String, DayData, Vec<journal::JournalPR>)> = Vec::new();
229→    for repo_path in &repo_paths {
230→        let repo_name = std::path::Path::new(repo_path)
231→            .file_name()
232→            .map(|n| n.to_string_lossy().to_string())
233→            .unwrap_or_else(|| "unknown".to_string());
234→
235→        let day_data = gather_day_data(repo_path, date).unwrap_or(DayData {
236→            summaries: Vec::new(),
237→            files_touched: Vec::new(),
238→            total_sessions: 0,
239→            total_tokens: 0,
240→            avg_ai_pct: 0,
241→            lines_changed: 0,
242→        });
243→
244→        let prs = github::fetch_prs_for_date(repo_path, date);
245→        all_repo_data.push((repo_name, day_data, prs));
246→    }
247→
248→    // Build prompt across all repos
249→    let prompt = build_multi_repo_prompt(date, &all_repo_data, &extra);
250→
251→    let api_key = config::read_app_settings()
252→        .anthropic_api_key
253→        .filter(|k| !k.is_empty())
254→        .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
255→        .ok_or_else(|| {
256→            "Anthropic API key is not configured. Set it in Settings or as ANTHROPIC_API_KEY env var."
257→                .to_string()
258→        })?;
259→
260→    let model = std::env::var("ANTHROPIC_MODEL")
261→        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
262→
263→    let client = reqwest::blocking::Client::builder()
264→        .timeout(std::time::Duration::from_secs(90))
265→        .build()
266→        .map_err(|e| format!("Failed to build HTTP client: {}", e))?;
267→
268→    let response = client
269→        .post("https://api.anthropic.com/v1/messages")
270→        .header("x-api-key", &api_key)
271→        .header("anthropic-version", "2023-06-01")
272→        .header("content-type", "application/json")
273→        .json(&AnthropicRequest {
274→            model,
275→            max_tokens: 2_000,
276→            temperature: 0.3,
277→            system: "You are a work journal assistant. Generate concise daily summaries of development work. Respond with JSON only.".to_string(),
278→            messages: vec![AnthropicMessage {
279→                role: "user".to_string(),
280→                content: prompt,
281→            }],
282→        })
283→        .send()
284→        .map_err(|e| format!("Anthropic request failed: {}", e))?
285→        .error_for_status()
286→        .map_err(|e| format!("Anthropic request failed: {}", e))?;
287→
288→    let body: AnthropicResponse = response
289→        .json()
290→        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
291→
292→    let text = body
293→        .content
294→        .into_iter()
295→        .filter(|block| block.kind == "text")
296→        .filter_map(|block| block.text)
297→        .collect::<Vec<_>>()
298→        .join("\n");
299→
300→    // Strip markdown code fences if present
301→    let json_text = text
302→        .trim()
303→        .trim_start_matches("```json")
304→        .trim_start_matches("```")
305→        .trim_end_matches("```")
306→        .trim();
307→
308→    let ai_response: AiResponse = serde_json::from_str(json_text)
309→        .map_err(|e| format!("Failed to parse AI response: {} — raw: {}", e, json_text))?;
310→
311→    // Build the full entry
312→    let generated_at = {
313→        let now = std::time::SystemTime::now()
314→            .duration_since(std::time::UNIX_EPOCH)
315→            .unwrap_or_default()
316→            .as_secs();
317→        format!("{}T00:00:00Z", journal::format_unix_date(now as i64))
318→    };
319→
320→    // Build a lookup from repo name to (day_data, prs)
321→    let repo_lookup: std::collections::HashMap<String, &(String, DayData, Vec<journal::JournalPR>)> =
322→        all_repo_data.iter().map(|r| (r.0.clone(), r)).collect();
323→
324→    // Map AI repo sections with their matching data
325→    let repos: Vec<journal::RepoSection> = ai_response
326→        .repos
327→        .into_iter()
328→        .map(|ai_repo| {
329→            let (lines_added, lines_removed, repo_prs) =
330→                if let Some((_, day_data, prs)) = repo_lookup.get(&ai_repo.name) {
331→                    (day_data.lines_changed / 2, day_data.lines_changed / 4, prs.clone())
332→                } else {
333→                    (0, 0, Vec::new())
334→                };
335→
336→            journal::RepoSection {
337→                name: ai_repo.name,
338→                lines_added,
339→                lines_removed,
340→                accomplishments: ai_repo.accomplishments,
341→                pull_requests: repo_prs,
342→            }
343→        })
344→        .collect();
345→
346→    // Aggregate stats across all repos
347→    let total_lines_changed: u64 = all_repo_data.iter().map(|(_, d, _)| d.lines_changed).sum();
348→    let total_sessions: u64 = all_repo_data.iter().map(|(_, d, _)| d.total_sessions).sum();
349→    let total_tokens: u64 = all_repo_data.iter().map(|(_, d, _)| d.total_tokens).sum();
350→    let total_prs: u64 = repos.iter().map(|r| r.pull_requests.len() as u64).sum();
351→    let avg_ai_pct = {
352→        let pcts: Vec<u64> = all_repo_data.iter().map(|(_, d, _)| d.avg_ai_pct).filter(|p| *p > 0).collect();
353→        if pcts.is_empty() { 0 } else { pcts.iter().sum::<u64>() / pcts.len() as u64 }
354→    };
355→
356→    let entry = journal::JournalEntry {
357→        date: date.to_string(),
358→        generated_at,
359→        repos,
360→        other_work: ai_response.other_work,
361→        stats: journal::JournalStats {
362→            lines_changed: total_lines_changed,
363→            sessions: total_sessions,
364→            prs: total_prs,
365→            ai_authored_pct: avg_ai_pct,
366→            tokens: total_tokens,
367→        },
368→    };
369→
370→    // Save to global journal dir
371→    journal::save_entry(&entry)?;
372→
373→    Ok(entry)
374→}
