100→/// Get a single journal entry by date (YYYY-MM-DD).
101→pub fn get_entry(date: &str) -> Result<JournalEntry, String> {
102→    let path = journal_dir().join(format!("{}.md", date));
103→    if !path.exists() {
104→        return Err(format!("No journal entry for {}", date));
105→    }
106→    let content = fs::read_to_string(&path)
107→        .map_err(|e| format!("Failed to read entry: {}", e))?;
108→    parse_markdown(&content)
109→}
