254→fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
255→    let mut repos = Vec::new();
256→    let mut other_work = Vec::new();
257→    let mut current_repo: Option<RepoSection> = None;
258→    let mut in_prs = false;
259→    let mut in_other_work = false;
260→
261→    for line in body.lines() {
262→        let trimmed = line.trim();
263→
264→        // H2 heading = repo name or "Other Work"
265→        if let Some(heading) = trimmed.strip_prefix("## ") {
266→            // Save previous repo
267→            if let Some(repo) = current_repo.take() {
268→                repos.push(repo);
269→            }
270→            in_prs = false;
271→
272→            if heading == "Other Work" {
273→                in_other_work = true;
274→                continue;
275→            }
276→
277→            in_other_work = false;
278→            current_repo = Some(RepoSection {
279→                name: heading.to_string(),
280→                lines_added: 0,
281→                lines_removed: 0,
282→                accomplishments: Vec::new(),
283→                pull_requests: Vec::new(),
284→            });
285→            continue;
286→        }
287→
288→        // H3 heading = "Pull Requests" subsection
289→        if trimmed.starts_with("### Pull Requests") {
290→            in_prs = true;
291→            continue;
292→        }
293→
294→        // Lines diff stats: _+716 -131_
295→        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
296→            if let Some(ref mut repo) = current_repo {
297→                let inner = &trimmed[1..trimmed.len() - 1];
298→                let parts: Vec<&str> = inner.split_whitespace().collect();
299→                if parts.len() == 2 {
300→                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
301→                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
302→                }
303→            }
304→            continue;
305→        }
306→
307→        // Bullet points
308→        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
309→            if in_other_work {
310→                other_work.push(bullet_content.to_string());
311→            } else if in_prs {
312→                if let Some(ref mut repo) = current_repo {
313→                    if let Some(pr) = parse_pr_line(bullet_content) {
314→                        repo.pull_requests.push(pr);
315→                    }
316→                }
317→            } else if let Some(ref mut repo) = current_repo {
318→                repo.accomplishments.push(bullet_content.to_string());
319→            }
320→        }
321→    }
322→
323→    // Don't forget last repo
324→    if let Some(repo) = current_repo {
325→        repos.push(repo);
326→    }
327→
328→    (repos, other_work)
329→}
