331→/// Parse a PR line like: [**title**](url) #142 — merged  OR  **title** #142 — merged
332→fn parse_pr_line(line: &str) -> Option<JournalPR> {
333→    let (title, url, rest) = if line.starts_with("[**") {
334→        // [**title**](url) #number — status
335→        let bold_end = line.find("**](")?;
336→        let title = line[3..bold_end].to_string();
337→        let url_start = bold_end + 4;
338→        let url_end = line[url_start..].find(')')? + url_start;
339→        let url = line[url_start..url_end].to_string();
340→        let rest = &line[url_end + 1..];
341→        (title, url, rest)
342→    } else {
343→        // **title** #number — status (legacy)
344→        let bold_start = line.find("**")?;
345→        let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
346→        let title = line[bold_start + 2..bold_end].to_string();
347→        let rest = &line[bold_end + 2..];
348→        (title, String::new(), rest)
349→    };
350→
351→    let hash_pos = rest.find('#')?;
352→    let after_hash = &rest[hash_pos + 1..];
353→
354→    // Find the number (digits until non-digit)
355→    let num_end = after_hash.find(|c: char| !c.is_ascii_digit()).unwrap_or(after_hash.len());
356→    let number: u64 = after_hash[..num_end].parse().ok()?;
357→
358→    // Find status after — or -
359→    let status = if let Some(dash_pos) = rest.find('—').or_else(|| rest.find(" - ")) {
360→        let s = rest[dash_pos..].trim_start_matches('—').trim_start_matches(" - ").trim();
361→        s.to_string()
362→    } else {
363→        "open".to_string()
364→    };
365→
366→    Some(JournalPR {
367→        title,
368→        number,
369→        status,
370→        additions: 0,
371→        deletions: 0,
372→        url,
373→    })
374→}
