376→/// Render a JournalEntry as a markdown string.
377→pub fn render_markdown(entry: &JournalEntry) -> String {
378→    let mut out = String::new();
379→
380→    // Frontmatter
381→    out.push_str("---\n");
382→    out.push_str(&format!("date: {}\n", entry.date));
383→    out.push_str(&format!("generated_at: {}\n", entry.generated_at));
384→
385→    // Repos list
386→    out.push_str("repos:\n");
387→    for repo in &entry.repos {
388→        out.push_str(&format!("  - {}\n", repo.name));
389→    }
390→
391→    // Stats
392→    out.push_str("stats:\n");
393→    out.push_str(&format!("  lines_changed: {}\n", entry.stats.lines_changed));
394→    out.push_str(&format!("  sessions: {}\n", entry.stats.sessions));
395→    out.push_str(&format!("  prs: {}\n", entry.stats.prs));
396→    out.push_str(&format!("  ai_authored_pct: {}\n", entry.stats.ai_authored_pct));
397→    out.push_str(&format!("  tokens: {}\n", entry.stats.tokens));
398→    out.push_str("---\n\n");
399→
400→    // Repo sections
401→    for repo in &entry.repos {
402→        out.push_str(&format!("## {}\n", repo.name));
403→        out.push_str(&format!("_+{} -{}_ \n\n", repo.lines_added, repo.lines_removed));
404→
405→        for item in &repo.accomplishments {
406→            out.push_str(&format!("- {}\n", item));
407→        }
408→
409→        if !repo.pull_requests.is_empty() {
410→            out.push_str("\n### Pull Requests\n");
411→            for pr in &repo.pull_requests {
412→                if pr.url.is_empty() {
413→                    out.push_str(&format!("- **{}** #{} — {}\n", pr.title, pr.number, pr.status));
414→                } else {
415→                    out.push_str(&format!("- [**{}**]({}) #{} — {}\n", pr.title, pr.url, pr.number, pr.status));
416→                }
417→            }
418→        }
419→
420→        out.push('\n');
421→    }
422→
423→    // Other work
424→    if !entry.other_work.is_empty() {
425→        out.push_str("## Other Work\n");
426→        for item in &entry.other_work {
427→            out.push_str(&format!("- {}\n", item));
428→        }
429→    }
430→
431→    out
432→}
