282→#[tauri::command]
283→fn get_checkpoint_logs(
284→    repo_path: String,
285→    checkpoint_id: String,
286→    session_ids: Vec<String>,
287→) -> Result<EntireLogResult, String> {
288→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
289→    if !log_path.exists() {
290→        return Ok(EntireLogResult {
291→            lines: Vec::new(),
292→            total_lines: 0,
293→            file_size_bytes: 0,
294→        });
295→    }
296→
297→    let metadata = std::fs::metadata(&log_path)
298→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
299→    let file_size_bytes = metadata.len();
300→
301→    let file = std::fs::File::open(&log_path)
302→        .map_err(|e| format!("Failed to open log file: {}", e))?;
303→
304→    let reader = BufReader::new(file);
305→    let mut matching_lines = Vec::new();
306→
307→    for line in reader.lines() {
308→        let line = match line {
309→            Ok(l) => l,
310→            Err(_) => continue,
311→        };
312→
313→        // Parse each line as JSON and check for matching session_id or checkpoint_id
314→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(&line) {
315→            let line_session_id = value.get("session_id").and_then(|v| v.as_str());
316→            let line_checkpoint_id = value.get("checkpoint_id").and_then(|v| v.as_str());
317→
318→            let matches = line_session_id
319→                .map(|sid| session_ids.iter().any(|s| s == sid))
320→                .unwrap_or(false)
321→                || line_checkpoint_id
322→                    .map(|cid| cid == checkpoint_id)
323→                    .unwrap_or(false);
324→
325→            if matches {
326→                matching_lines.push(line);
327→            }
328→        }
329→    }
330→
331→    Ok(EntireLogResult {
332→        total_lines: matching_lines.len() as u32,
333→        lines: matching_lines,
334→        file_size_bytes,
335→    })
336→}
