614→fn generate_review_run_id() -> String {
615→    let now = std::time::SystemTime::now()
616→        .duration_since(std::time::UNIX_EPOCH)
617→        .unwrap_or_default();
618→    format!("review-{}-{}", now.as_secs(), now.subsec_nanos())
619→}
