622→fn get_checkpoint_diff(
623→    repo_path: String,
624→    commit_sha: String,
625→) -> Result<Vec<FileDiff>, String> {
626→    if commit_sha.is_empty() {
627→        return Err("No commit SHA available for this checkpoint".to_string());
628→    }
629→
630→    let repo = git::open_repo(&repo_path)?;
631→    collect_checkpoint_diff(&repo, &commit_sha)
