788→pub fn run() {
789→    tauri::Builder::default()
790→        .plugin(tauri_plugin_opener::init())
791→        .plugin(tauri_plugin_dialog::init())
792→        .plugin(tauri_plugin_window_state::Builder::default().build())
793→        .manage(Mutex::new(AppState {
794→            watched_repos: HashSet::new(),
795→        }))
796→        .manage(Mutex::new(ghostty::GhosttyState::new()))
797→        .setup(|app| {
798→            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
799→            // ghostty_app_tick processes Cocoa/Metal events and must run on the
800→            // main thread.
801→            {
802→                use block2::RcBlock;
803→                use objc2_foundation::NSTimer;
804→
805→                let handle = app.handle().clone();
806→                let tick_block = RcBlock::new(move |_timer| {
807→                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
808→                    let mutex = state.inner();
809→                    if let Ok(gs) = mutex.lock() {
810→                        if let Some(app) = gs.app.as_ref() {
811→                            app.tick();
812→                        }
813→                    }
814→                });
815→
816→                let _tick_timer = unsafe {
817→                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
818→                        1.0 / 60.0,
819→                        true,
820→                        &tick_block,
821→                    )
822→                };
823→            }
824→
825→            // System tray
826→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
827→            use tauri::tray::TrayIconBuilder;
828→            use tauri::Manager;
829→
830→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
831→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
832→            let menu = MenuBuilder::new(app)
833→                .item(&show)
834→                .separator()
835→                .item(&quit)
836→                .build()?;
837→
838→            let _tray = TrayIconBuilder::new()
839→                .tooltip("Entire Desktop")
840→                .menu(&menu)
841→                .on_menu_event(move |app, event| {
842→                    match event.id().as_ref() {
843→                        "show" => {
844→                            if let Some(window) = app.get_webview_window("main") {
845→                                let _ = window.show();
846→                                let _ = window.set_focus();
847→                            }
848→                        }
849→                        "quit" => {
850→                            app.exit(0);
851→                        }
852→                        _ => {}
853→                    }
854→                })
855→                .on_tray_icon_event(|tray, event| {
856→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
857→                        let app = tray.app_handle();
858→                        if let Some(window) = app.get_webview_window("main") {
859→                            let _ = window.show();
860→                            let _ = window.set_focus();
861→                        }
862→                    }
863→                })
864→                .build(app)?;
865→
866→            Ok(())
867→        })
868→        .invoke_handler(tauri::generate_handler![
869→            debug_log,
870→            list_repos,
871→            register_repo,
872→            unregister_repo,
873→            block_repo,
874→            get_app_settings,
875→            save_app_settings,
876→            create_worktree,
877→            delete_worktree,
878→            delete_branch,
879→            list_checkpoints,
880→            get_transcript,
881→            get_checkpoint_diff,
882→            run_checkpoint_semantic_review,
883→            get_branch_diff,
884→            list_sessions,
885→            get_entire_settings,
886→            get_entire_logs,
887→            get_checkpoint_logs,
888→            get_raw_checkpoint_metadata,
889→            get_raw_session_file,
890→            launch_ghostty_agent,
891→            list_trails,
892→            watch_repo,
893→            ghostty::commands::ghostty_create_surface,
894→            ghostty::commands::ghostty_destroy_surface,
895→            ghostty::commands::ghostty_update_overlay,
896→            ghostty::commands::ghostty_show_overlay,
897→            ghostty::commands::ghostty_focus_overlay,
898→            ghostty::commands::ghostty_send_text,
899→            list_journal_entries,
900→            get_journal_entry,
901→            generate_journal_entry,
902→            get_journal_dates,
903→        ])
904→        .run(tauri::generate_context!())
905→        .expect("error while running tauri application");
906→}
