 12→use std::collections::HashSet;
 13→use std::io::{BufRead, BufReader};
 14→use std::sync::Mutex;
 15→use tauri::{Emitter, State};
 16→
 17→struct AppState {
 18→    watched_repos: HashSet<String>,
 19→}
 20→
 21→#[tauri::command]
 22→fn debug_log(message: String) -> Result<(), String> {
 23→    use std::io::Write;
 24→    let timestamp = std::time::SystemTime::now()
 25→        .duration_since(std::time::UNIX_EPOCH)
 26→        .unwrap_or_default();
 27→    let line = format!(
 28→        "[{}.{:03}] [frontend] {}\n",
 29→        timestamp.as_secs(),
 30→        timestamp.subsec_millis(),
 31→        message
 32→    );
 33→    std::fs::OpenOptions::new()
 34→        .create(true)
 35→        .append(true)
 36→        .open("/tmp/entire-terminal-debug.log")
 37→        .and_then(|mut f| f.write_all(line.as_bytes()))
 38→        .map_err(|e| format!("Failed to write debug log: {}", e))
 39→}
 40→
 41→#[tauri::command]
 42→fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
 43→    let repo_paths = config::discover_repos();
 44→    let registered = config::get_registered_repos();
 45→    let registered_set: HashSet<String> = registered.into_iter().collect();
 46→    let mut repos = Vec::new();
 47→    for path in repo_paths {
 48→        match git::get_repo_info(&path) {
 49→            Ok(mut info) => {
 50→                info.registered = registered_set.contains(&path);
 51→                repos.push(info);
 52→            }
 53→            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
 54→        }
 55→    }
 56→    Ok(repos)
 57→}
