424→/// Convert a git2::Diff into our FileDiff structs
425→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
426→    let mut files: Vec<FileDiff> = Vec::new();
427→
428→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
429→        let path = delta
430→            .new_file()
431→            .path()
432→            .or_else(|| delta.old_file().path())
433→            .map(|p| p.to_string_lossy().to_string())
434→            .unwrap_or_default();
435→
436→        let status = match delta.status() {
437→            git2::Delta::Added => "added",
438→            git2::Delta::Deleted => "deleted",
439→            _ => "modified",
440→        };
441→
442→        // Ensure we have a FileDiff entry for this path
443→        if files.last().map_or(true, |f| f.path != path) {
444→            files.push(FileDiff {
445→                path: path.clone(),
446→                status: status.to_string(),
447→                hunks: Vec::new(),
448→            });
449→        }
450→
451→        let file = files.last_mut().unwrap();
452→
453→        // New hunk
454→        if let Some(h) = hunk {
455→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
456→            if file.hunks.last().map_or(true, |last| last.header != header) {
457→                file.hunks.push(DiffHunk {
458→                    header,
459→                    lines: Vec::new(),
460→                });
461→            }
462→        }
463→
464→        // Diff line
465→        if let Some(current_hunk) = file.hunks.last_mut() {
466→            let kind = match line.origin() {
467→                '+' => "add",
468→                '-' => "delete",
469→                ' ' => "context",
470→                _ => return true,
471→            };
472→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
473→            current_hunk.lines.push(DiffLine {
474→                kind: kind.to_string(),
475→                content,
476→                old_lineno: line.old_lineno(),
477→                new_lineno: line.new_lineno(),
478→            });
479→        }
480→
481→        true
482→    })
483→    .map_err(|e| format!("Failed to print diff: {}", e))?;
484→
485→    Ok(files)
486→}
487→
488→fn collect_checkpoint_diff(
489→    repo: &git2::Repository,
490→    commit_sha: &str,
491→) -> Result<Vec<FileDiff>, String> {
492→    let oid = git2::Oid::from_str(commit_sha)
493→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
494→    let commit = repo
495→        .find_commit(oid)
496→        .map_err(|e| format!("Commit not found: {}", e))?;
497→
498→    let tree = commit
499→        .tree()
500→        .map_err(|e| format!("Failed to get tree: {}", e))?;
501→
502→    let parent_tree = commit.parent(0).ok().and_then(|p| p.tree().ok());
503→
504→    let diff = repo
505→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
506→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
507→
508→    collect_diff_files(&diff)
509→}
