668→#[tauri::command]
669→fn get_branch_diff(
670→    repo_path: String,
671→    branch: String,
672→) -> Result<Vec<FileDiff>, String> {
673→    let repo = git::open_repo(&repo_path)?;
674→
675→    // Resolve the branch HEAD
676→    let branch_ref = repo
677→        .find_branch(&branch, git2::BranchType::Local)
678→        .map_err(|e| format!("Branch not found: {}", e))?;
679→    let branch_commit = branch_ref
680→        .get()
681→        .peel_to_commit()
682→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
683→
684→    // Find the default branch (try main, then master)
685→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
686→        "main"
687→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
688→        "master"
689→    } else {
690→        return Err("No default branch (main/master) found".to_string());
691→    };
692→
693→    // If we're diffing the default branch against itself, return empty
694→    if branch == default_branch_name {
695→        return Ok(Vec::new());
696→    }
697→
698→    let default_ref = repo
699→        .find_branch(default_branch_name, git2::BranchType::Local)
700→        .map_err(|e| format!("Default branch error: {}", e))?;
701→    let default_commit = default_ref
702→        .get()
703→        .peel_to_commit()
704→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
705→
706→    // Find merge base
707→    let merge_base_oid = repo
708→        .merge_base(default_commit.id(), branch_commit.id())
709→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
710→    let merge_base_commit = repo
711→        .find_commit(merge_base_oid)
712→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
713→
714→    let base_tree = merge_base_commit
715→        .tree()
716→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
717→    let branch_tree = branch_commit
718→        .tree()
719→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
720→
721→    let diff = repo
722→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
723→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
724→
725→    collect_diff_files(&diff)
726→}
